void printVector(const Vector2D& v, const std::string& name) {
    std::cout << name << " = (" << v.x << ", " << v.y << ")" << std::endl;
}

int main() {
    Vector2D v1(1.0, 2.0);
    Vector2D v2(3.0, 4.0);
    Vector2D v3 = v1 + v2;
    printVector(v3, "v3");

    Vector2D v4(-0.5, 10.0);
    Vector2D v5(1.5, -3.0);
    Vector2D v6 = v4 + v5;
    printVector(v6, "v6");

    return 0;
}
